--
-- Name: artigos_busca_trigger(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.artigos_busca_trigger() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    NEW.busca_vetor := 
        setweight(to_tsvector('portuguese', COALESCE(NEW.titulo, '')), 'A') ||
        setweight(to_tsvector('portuguese', COALESCE(NEW.resumo, '')), 'B') ||
        setweight(to_tsvector('portuguese', COALESCE(NEW.conteudo, '')), 'C');
    RETURN NEW;
END;
$$;


--
-- Name: audit_extract_registro_id(jsonb); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.audit_extract_registro_id(payload jsonb) RETURNS uuid
    LANGUAGE plpgsql
    AS $$
DECLARE
  raw_id TEXT;
BEGIN
  IF payload IS NULL THEN
    RETURN NULL;
  END IF;

  raw_id := COALESCE(
    payload->>'id',
    payload->>'id_repositorio_recorda'
  );

  IF raw_id IS NULL OR LENGTH(TRIM(raw_id)) = 0 THEN
    RETURN NULL;
  END IF;

  RETURN raw_id::UUID;
EXCEPTION
  WHEN invalid_text_representation THEN
    RETURN NULL;
END;
$$;


--
-- Name: audit_trigger_function(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.audit_trigger_function() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  old_data JSONB;
  new_data JSONB;
  op tipo_operacao;
  ref_id UUID;
BEGIN
  IF TG_OP = 'INSERT' THEN
    old_data := NULL;
    new_data := to_jsonb(NEW);
    op := 'INSERT';
    ref_id := audit_extract_registro_id(new_data);

    IF ref_id IS NULL THEN
      RAISE EXCEPTION 'Audit trigger: não foi possível extrair identificador do registro em % (INSERT)', TG_TABLE_NAME;
    END IF;

    INSERT INTO auditoria (tabela, registro_id, operacao, dados_anteriores, dados_novos)
    VALUES (TG_TABLE_NAME, ref_id, op, old_data, new_data);

    RETURN NEW;
  ELSIF TG_OP = 'UPDATE' THEN
    old_data := to_jsonb(OLD);
    new_data := to_jsonb(NEW);
    op := 'UPDATE';
    ref_id := COALESCE(audit_extract_registro_id(new_data), audit_extract_registro_id(old_data));

    IF ref_id IS NULL THEN
      RAISE EXCEPTION 'Audit trigger: não foi possível extrair identificador do registro em % (UPDATE)', TG_TABLE_NAME;
    END IF;

    INSERT INTO auditoria (tabela, registro_id, operacao, dados_anteriores, dados_novos)
    VALUES (TG_TABLE_NAME, ref_id, op, old_data, new_data);

    RETURN NEW;
  ELSIF TG_OP = 'DELETE' THEN
    old_data := to_jsonb(OLD);
    new_data := NULL;
    op := 'DELETE';
    ref_id := audit_extract_registro_id(old_data);

    IF ref_id IS NULL THEN
      RAISE EXCEPTION 'Audit trigger: não foi possível extrair identificador do registro em % (DELETE)', TG_TABLE_NAME;
    END IF;

    INSERT INTO auditoria (tabela, registro_id, operacao, dados_anteriores, dados_novos)
    VALUES (TG_TABLE_NAME, ref_id, op, old_data, new_data);

    RETURN OLD;
  END IF;

  RETURN NULL;
END;
$$;


