--
-- Name: check_registros_producao_immutable(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.check_registros_producao_immutable() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF OLD.cancelado = FALSE AND NEW.cancelado = TRUE THEN
        -- Permitir apenas cancelamento
        IF NEW.processo_id != OLD.processo_id OR
           NEW.volume_id IS DISTINCT FROM OLD.volume_id OR
           NEW.etapa_id != OLD.etapa_id OR
           NEW.colaborador_id != OLD.colaborador_id OR
           NEW.fonte_dados_id != OLD.fonte_dados_id OR
           NEW.quantidade != OLD.quantidade OR
           NEW.data_registro != OLD.data_registro OR
           NEW.data_producao != OLD.data_producao OR
           NEW.observacao != OLD.observacao THEN
            RAISE EXCEPTION 'Campos imutáveis não podem ser alterados';
        END IF;
        RETURN NEW;
    ELSIF OLD.cancelado = TRUE THEN
        RAISE EXCEPTION 'Registro cancelado não pode ser alterado';
    ELSE
        RAISE EXCEPTION 'Registro de produção é imutável, apenas cancelamento é permitido';
    END IF;
END;
$$;


--
-- Name: fn_aplicar_resultado_cq_em_repositorios(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_aplicar_resultado_cq_em_repositorios() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  item RECORD;
BEGIN
  IF NEW.status = 'FECHADO' AND OLD.status <> NEW.status THEN
    FOR item IN
      SELECT repositorio_id, resultado
      FROM lotes_controle_qualidade_itens
      WHERE lote_id = NEW.id
    LOOP
      IF item.resultado = 'APROVADO' THEN
        UPDATE repositorios
        SET status_atual = 'ENTREGUE',
            etapa_atual = 'ENTREGA'
        WHERE id_repositorio_recorda = item.repositorio_id;

        INSERT INTO historico_etapas (
          repositorio_id,
          etapa_origem,
          etapa_destino,
          status_origem,
          status_destino,
          usuario_id,
          detalhes
        )
        VALUES (
          item.repositorio_id,
          'CONTROLE_QUALIDADE',
          'ENTREGA',
          'EM_CQ',
          'ENTREGUE',
          NEW.auditor_id,
          jsonb_build_object('origem', 'lote_cq', 'lote_id', NEW.id)
        );
      ELSIF item.resultado = 'REPROVADO' THEN
        UPDATE repositorios
        SET status_atual = 'CQ_REPROVADO',
            etapa_atual = 'CONFERENCIA'
        WHERE id_repositorio_recorda = item.repositorio_id;

        INSERT INTO historico_etapas (
          repositorio_id,
          etapa_origem,
          etapa_destino,
          status_origem,
          status_destino,
          usuario_id,
          detalhes
        )
        VALUES (
          item.repositorio_id,
          'CONTROLE_QUALIDADE',
          'CONFERENCIA',
          'EM_CQ',
          'CQ_REPROVADO',
          NEW.auditor_id,
          jsonb_build_object('origem', 'lote_cq', 'lote_id', NEW.id)
        );
      END IF;
    END LOOP;
  END IF;

  RETURN NEW;
END;
$$;


--
-- Name: fn_validar_avanco_etapa_repositorio(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_validar_avanco_etapa_repositorio() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  checklist_concluido BOOLEAN;
  ultima_movimentacao tipo_movimentacao_armario;
BEGIN
  IF NEW.etapa_atual <> OLD.etapa_atual THEN
    SELECT EXISTS (
      SELECT 1
      FROM checklists
      WHERE repositorio_id = OLD.id_repositorio_recorda
        AND etapa = OLD.etapa_atual
        AND status = 'CONCLUIDO'
    ) INTO checklist_concluido;

    IF NOT checklist_concluido THEN
      RAISE EXCEPTION 'Não é permitido avançar etapa sem checklist concluído da etapa %', OLD.etapa_atual;
    END IF;

    SELECT m.tipo_movimentacao
    INTO ultima_movimentacao
    FROM movimentacoes_armario m
    WHERE m.repositorio_id = OLD.id_repositorio_recorda
      AND m.etapa = OLD.etapa_atual
    ORDER BY m.data_movimentacao DESC
    LIMIT 1;

    IF ultima_movimentacao IS DISTINCT FROM 'DEVOLUCAO' THEN
      RAISE EXCEPTION 'Não é permitido avançar etapa sem devolução do repositório ao armário';
    END IF;

    NEW.historico_de_etapas :=
      COALESCE(OLD.historico_de_etapas, '[]'::jsonb) ||
      jsonb_build_array(
        jsonb_build_object(
          'etapa_origem', OLD.etapa_atual,
          'etapa_destino', NEW.etapa_atual,
          'status_origem', OLD.status_atual,
          'status_destino', NEW.status_atual,
          'data_evento', CURRENT_TIMESTAMP
        )
      );
  END IF;

  RETURN NEW;
END;
$$;


--
-- Name: fn_validar_conclusao_checklist(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_validar_conclusao_checklist() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  total_obrigatorios INTEGER;
  total_preenchidos INTEGER;
BEGIN
  IF OLD.status = 'CONCLUIDO' AND NEW.status = 'ABERTO' THEN
    RAISE EXCEPTION 'Checklist concluído não pode ser reaberto';
  END IF;

  IF NEW.status = 'CONCLUIDO' AND OLD.status <> NEW.status THEN
    SELECT COUNT(*) INTO total_obrigatorios
    FROM checklist_modelos
    WHERE etapa = NEW.etapa
      AND obrigatorio = TRUE
      AND ativo = TRUE;

    -- Se não há modelos obrigatórios para a etapa, permitir conclusão
    IF total_obrigatorios > 0 THEN
      SELECT COUNT(*) INTO total_preenchidos
      FROM checklist_itens i
      JOIN checklist_modelos m ON m.id = i.modelo_id
      WHERE i.checklist_id = NEW.id
        AND m.etapa = NEW.etapa
        AND m.obrigatorio = TRUE
        AND m.ativo = TRUE;

      IF total_preenchidos < total_obrigatorios THEN
        RAISE EXCEPTION 'Checklist incompleto: % de % itens obrigatórios preenchidos', total_preenchidos, total_obrigatorios;
      END IF;
    END IF;

    NEW.data_conclusao := COALESCE(NEW.data_conclusao, CURRENT_TIMESTAMP);
    NEW.ativo := FALSE;
  END IF;

  RETURN NEW;
END;
$$;


--
-- Name: fn_validar_fechamento_lote_cq(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_validar_fechamento_lote_cq() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  total_itens INTEGER;
  total_pendentes INTEGER;
BEGIN
  IF NEW.status = 'FECHADO' AND OLD.status <> NEW.status THEN
    SELECT COUNT(*) INTO total_itens
    FROM lotes_controle_qualidade_itens
    WHERE lote_id = NEW.id;

    IF total_itens <> 10 THEN
      RAISE EXCEPTION 'Lote de CQ deve conter exatamente 10 repositórios. Total atual: %', total_itens;
    END IF;

    SELECT COUNT(*) INTO total_pendentes
    FROM lotes_controle_qualidade_itens
    WHERE lote_id = NEW.id
      AND resultado = 'PENDENTE';

    IF total_pendentes > 0 THEN
      RAISE EXCEPTION 'Não é possível fechar lote de CQ com itens pendentes';
    END IF;

    NEW.data_fechamento := COALESCE(NEW.data_fechamento, CURRENT_TIMESTAMP);
  END IF;

  RETURN NEW;
END;
$$;


--
-- Name: fn_validar_producao_com_checklist_ativo(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_validar_producao_com_checklist_ativo() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  checklist_valido INTEGER;
BEGIN
  SELECT COUNT(*) INTO checklist_valido
  FROM checklists
  WHERE id = NEW.checklist_id
    AND repositorio_id = NEW.repositorio_id
    AND etapa = NEW.etapa
    AND status = 'ABERTO'
    AND ativo = TRUE;

  IF checklist_valido = 0 THEN
    RAISE EXCEPTION 'Produção exige checklist ativo da mesma etapa e repositório';
  END IF;

  RETURN NEW;
END;
$$;


