--
-- Name: armarios; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.armarios (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    codigo character varying(50) NOT NULL,
    descricao character varying(255) DEFAULT ''::character varying NOT NULL,
    ativo boolean DEFAULT true NOT NULL,
    criado_em timestamp with time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    atualizado_em timestamp with time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    CONSTRAINT armarios_codigo_not_empty CHECK ((length(TRIM(BOTH FROM codigo)) > 0))
);


--
-- Name: auditoria; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.auditoria (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tabela character varying(100) NOT NULL,
    registro_id uuid NOT NULL,
    operacao public.tipo_operacao NOT NULL,
    dados_anteriores jsonb,
    dados_novos jsonb,
    colaborador_id uuid,
    ip_origem character varying(45),
    user_agent text,
    data_operacao timestamp with time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    CONSTRAINT auditoria_data_not_future CHECK ((data_operacao <= CURRENT_TIMESTAMP)),
    CONSTRAINT auditoria_tabela_not_empty CHECK ((length(TRIM(BOTH FROM tabela)) > 0))
);


--
-- Name: checklist_itens; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.checklist_itens (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    checklist_id uuid NOT NULL,
    modelo_id uuid NOT NULL,
    resultado public.resultado_item_checklist NOT NULL,
    observacao character varying(1000) DEFAULT ''::character varying NOT NULL,
    responsavel_id uuid NOT NULL,
    data_hora timestamp with time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    CONSTRAINT checklist_item_observacao_nonconforme CHECK (((resultado = 'CONFORME'::public.resultado_item_checklist) OR (length(TRIM(BOTH FROM observacao)) > 0)))
);


--
-- Name: checklist_modelos; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.checklist_modelos (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    etapa public.etapa_fluxo NOT NULL,
    codigo character varying(100) NOT NULL,
    descricao character varying(400) NOT NULL,
    obrigatorio boolean DEFAULT true NOT NULL,
    ordem integer NOT NULL,
    ativo boolean DEFAULT true NOT NULL,
    criado_em timestamp with time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    atualizado_em timestamp with time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    CONSTRAINT checklist_modelo_codigo_not_empty CHECK ((length(TRIM(BOTH FROM codigo)) > 0)),
    CONSTRAINT checklist_modelo_descricao_not_empty CHECK ((length(TRIM(BOTH FROM descricao)) > 0)),
    CONSTRAINT checklist_modelo_ordem_non_negative CHECK ((ordem >= 0))
);


--
-- Name: checklists; Type: TABLE; Schema: public; Owner: -
