    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    repositorio_id uuid NOT NULL,
    etapa public.etapa_fluxo NOT NULL,
    status public.status_checklist DEFAULT 'ABERTO'::public.status_checklist NOT NULL,
    observacao character varying(1000) DEFAULT ''::character varying NOT NULL,
    responsavel_id uuid NOT NULL,
    data_abertura timestamp with time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    data_conclusao timestamp with time zone,
    ativo boolean DEFAULT true NOT NULL,
    criado_em timestamp with time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    atualizado_em timestamp with time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    CONSTRAINT checklists_status_consistencia CHECK ((((status = 'ABERTO'::public.status_checklist) AND (data_conclusao IS NULL) AND (ativo = true)) OR ((status = 'CONCLUIDO'::public.status_checklist) AND (data_conclusao IS NOT NULL) AND (ativo = false))))
);


